-- 2. Szolgaltatok beszurasa
INSERT INTO public.providers (
  id, user_id, full_name, email, phone, description,
  category, county, website, avatar_url, approval_status, view_count, created_at
) VALUES
('10000001-0000-0000-0000-000000000001','00000001-0000-0000-0000-000000000001','Nagy Albert Gabor','nagy.albert.test@gmail.com','+36707888787','Vállalok fotózást esküvőkre! 30 éves szaktudással rendelkezem, rugalmasan dolgozom. Riport és beállított képek egyaránt. Digitális és nyomtatott albumok igény szerint.','fotosok-videosok','Budapest','https://www.nagyalbertfoto.hu',null,'approved',36,now() - interval '30 days'),
('10000001-0000-0000-0000-000000000002','00000001-0000-0000-0000-000000000002','Kovacs Peter Fotografia','kovacs.peter.foto.test@gmail.com','+36301234567','Esküvői fotós és videós vagyok, modern stílusban dolgozom. Drón felvételekkel is tudok szolgálni. Egész napos jelenlét vállalható, emlékezetes pillanatok megörökítése a célom.','fotosok-videosok','Pest','https://kovacsfilm.hu',null,'approved',89,now() - interval '45 days'),
('10000001-0000-0000-0000-000000000003','00000001-0000-0000-0000-000000000003','Szabo Reka Wedding Photography','reka.szabo.foto.test@gmail.com','+36209876543','Intim, életközeli képek a ti nagy napotokról. Riportstílusú fotózás, természetes pillanatok megörökítése a szívügyem. Győr és környéke, de vidékre is szívesen megyek.','fotosok-videosok','Győr-Moson-Sopron',null,null,'approved',54,now() - interval '20 days'),
('10000001-0000-0000-0000-000000000004','00000001-0000-0000-0000-000000000004','Horvath Filmstudio','horvath.film.test@outlook.com','+36706543210','4K videó és fotó csomag esküvőkre. Drón felvételek, highlight film, teljes nap rögzítése. Díjnyertes munkák, több éves tapasztalat esküvői helyszíneken.','fotosok-videosok','Baranya','https://horvathfilm.hu',null,'approved',112,now() - interval '60 days'),
('10000001-0000-0000-0000-000000000005','00000001-0000-0000-0000-000000000005','Kiss Balazs Eskuvoi Fotos','kissbalazsfoto.test@gmail.com','+36301112233','Természetes fény, valódi érzelmek. Budapest és vidék, utazási díj nélkül 150 km-ig. Stílusos, romantikus képek, amelyeket évtizedek múlva is szívesen nézegetnek.','fotosok-videosok','Fejér',null,null,'approved',41,now() - interval '15 days'),
('10000001-0000-0000-0000-000000000006','00000001-0000-0000-0000-000000000006','Fekete Adam Videography','adam.fekete.video.test@gmail.com','+36209998877','Filmszerű esküvői videók, storytelling megközelítéssel. Profi hangfelvétel, cinematic effektek. Előzetes megtekinthető a weboldalon, referenciák igény szerint.','fotosok-videosok','Borsod-Abaúj-Zemplén','https://feketeadam.hu',null,'approved',67,now() - interval '25 days'),
('10000001-0000-0000-0000-000000000007','00000001-0000-0000-0000-000000000007','Molnar Zsuzsanna Fotostudio','molnar.zsu.foto.test@gmail.com','+36701234000','Esküvői fotózás Debrecenben és környékén. Párfotózás lehetséges a nagy nap előtt is – így biztosan kényelmesen érzed magad a kamera előtt az esküvőn.','fotosok-videosok','Hajdú-Bihar',null,null,'approved',28,now() - interval '10 days'),
('10000001-0000-0000-0000-000000000008','00000001-0000-0000-0000-000000000008','DJ Tamas Eskuvoi Zenész','djtamas.test@gmail.com','+36305556677','Esküvői DJ és MC szolgáltatás. 15 éves tapasztalat, profi hangrendszer, fénytechnika. Az esti buli garantált – minden korosztálynak megfelelő zenei összeállítással.','elo-zene-dj','Budapest','https://djtamas.hu',null,'approved',95,now() - interval '40 days'),
('10000001-0000-0000-0000-000000000009','00000001-0000-0000-0000-000000000009','Harmonia Zenekar','harmonia.zenekar.test@gmail.com','+36204445566','5 tagú élőzene zenekar. Magyar nóta, pop, jazz és rock repertoár. Vonós kvartett lehetőség a szertartáshoz, tánczene az esti mulatsághoz.','elo-zene-dj','Pest','https://harmoniazenekar.hu',null,'approved',78,now() - interval '35 days'),
('10000001-0000-0000-0000-000000000010','00000001-0000-0000-0000-000000000010','Varga Norbert Szaxofonista','varga.norbi.szax.test@gmail.com','+36703334455','Szólóban vagy kisegyüttessel vállalok esküvői zenei szolgáltatást. Jazz, soul, pop – bármelyik hangulathoz igazodok. A szertartástól az esti buliig jelen vagyok.','elo-zene-dj','Győr-Moson-Sopron',null,null,'approved',33,now() - interval '18 days'),
('10000001-0000-0000-0000-000000000011','00000001-0000-0000-0000-000000000011','DJ Krisztian Sound','djkrisztian.test@gmail.com','+36301231234','Profi DJ és fénytechnika minden stílusban. Interaktív műsorvezetés, modern és retró slágerek egyaránt. Referenciák megtekinthetők, egyedi igények megbeszélhetők.','elo-zene-dj','Somogy',null,null,'approved',44,now() - interval '22 days'),
('10000001-0000-0000-0000-000000000012','00000001-0000-0000-0000-000000000012','Melodia Vonosnegyes','melodia.vonos.test@gmail.com','+36207778899','Klasszikus és kortárs darabok esküvői szertartásokhoz és fogadásokhoz. Budapest és vidék egyaránt. Élő vonószene, amely örökre emlékezetessé teszi a nagy napot.','elo-zene-dj','Budapest','https://melodia.hu',null,'approved',56,now() - interval '28 days'),
('10000001-0000-0000-0000-000000000013','00000001-0000-0000-0000-000000000013','Toth Sandor Vofely','toth.sandor.vofely.test@gmail.com','+36306667788','Humoros és megható vőfélykedés. 20 éves tapasztalat, egyedi köszöntők írása. Egész napos jelenlét, programszervezés, a vendégek szórakoztatása garantált.','vofely','Budapest',null,null,'approved',62,now() - interval '50 days'),
('10000001-0000-0000-0000-000000000014','00000001-0000-0000-0000-000000000014','Balogh Tibor Vofely','balogh.tibor.vofely.test@gmail.com','+36205554433','Népi hagyományokat ötvöz a modern vőfélykedéssel. Versek, mondókák, játékok a vendégek szórakoztatásához. Debrecen és Hajdú-Bihar megye területén vállalok munkát.','vofely','Hajdú-Bihar',null,null,'approved',39,now() - interval '16 days'),
('10000001-0000-0000-0000-000000000015','00000001-0000-0000-0000-000000000015','Simon Peter Ceremoniasmester','simon.peter.mc.test@gmail.com','+36701110022','Kétnyelvű (magyar–angol) ceremóniamester. Vegyes házasságokhoz ideális. Profi, elegáns, megbízható. A teljes szertartást és a fogadást is levezeti igény szerint.','vofely','Pest','https://simonpetermc.hu',null,'approved',47,now() - interval '32 days'),
('10000001-0000-0000-0000-000000000016','00000001-0000-0000-0000-000000000016','Edessegek Haza Papp Katalin','papp.katalin.torta.test@gmail.com','+36209998800','Kézzel készített esküvői torták, macaronok, desszertek. Több réteg, saját készítésű fondant díszítés. Kóstolót vállalok, az ízek legalább olyan fontosak, mint a megjelenés.','torta-sutemeny','Budapest',null,null,'approved',88,now() - interval '55 days'),
('10000001-0000-0000-0000-000000000017','00000001-0000-0000-0000-000000000017','Mezeskalacs es Torta Manufaktura','mezeskalacs.manufaktura.test@gmail.com','+36303332211','Egyedi esküvői torták és mézeskalács favoritok. Allergiás változatok is elérhetők. Szállítás Budapest és Pest megye területén. Előzetes konzultáció ingyenes.','torta-sutemeny','Pest','https://mezesmanufaktura.hu',null,'approved',71,now() - interval '38 days'),
('10000001-0000-0000-0000-000000000018','00000001-0000-0000-0000-000000000018','Bartal Zsofia Cukraszda','bartal.zsofi.cukor.test@gmail.com','+36701234321','Naked cake, drip cake, tower cake – minden esküvői stílushoz. Győr és környéke, vidékre szállítással. Kóstolóval egybekötött tervezési konzultáció elérhető.','torta-sutemeny','Győr-Moson-Sopron',null,null,'approved',29,now() - interval '12 days'),
('10000001-0000-0000-0000-000000000019','00000001-0000-0000-0000-000000000019','Debreceni Cukraszmester','debr.cukor.test@gmail.com','+36204321098','Hagyományos és modern esküvői torták Debrecenben. 30 éves tapasztalat, megbízható minőség. Rendeld meg legalább 6 héttel az esküvő előtt a biztonság kedvéért.','torta-sutemeny','Hajdú-Bihar',null,null,'approved',52,now() - interval '42 days'),
('10000001-0000-0000-0000-000000000020','00000001-0000-0000-0000-000000000020','Alom Menyasszonyi Szalon','alom.menyasszonyi.test@gmail.com','+36301234888','Exkluzív és megfizethető menyasszonyi ruhák. Saját tervezésű és import modellek. Varrodai módosítás helyben elvégezhető. Időpontot kérj online vagy telefonon.','menyasszonyi-ruha','Budapest','https://alommenyasszonyi.hu',null,'approved',134,now() - interval '70 days'),
('10000001-0000-0000-0000-000000000021','00000001-0000-0000-0000-000000000021','Feher Rozsa Eskuvoi Szalon','feher.rozsa.szalon.test@gmail.com','+36205671234','Több száz ruhamodell raktárról. Bérlés és vásárlás egyaránt. Kiegészítők, fátyol, tiara – minden egy helyen. Debreceni szalon, baráti árakkal.','menyasszonyi-ruha','Hajdú-Bihar',null,null,'approved',98,now() - interval '48 days'),
('10000001-0000-0000-0000-000000000022','00000001-0000-0000-0000-000000000022','Gentlemans Club Oltonyos','gentlemans.oltonya.test@gmail.com','+36706781234','Méretre szabott öltönyök és szmoningok esküvőkre. Magyar szabó mesterek munkája. Bérlés lehetséges, és az öltönyt saját ízlésed szerint személyre szabhatjuk.','oltonya-szmoking','Budapest','https://gentlemans.hu',null,'approved',76,now() - interval '44 days'),
('10000001-0000-0000-0000-000000000023','00000001-0000-0000-0000-000000000023','Elegancia Oltonyaz','elegancia.oltonya.test@gmail.com','+36209870987','Prémium öltönyök és kiegészítők bérlése és vásárlása. Gyors kiszolgálás, barátságos árak. Pest megye egész területén elérhető, előzetes bejelentkezés ajánlott.','oltonya-szmoking','Pest',null,null,'approved',43,now() - interval '21 days'),
('10000001-0000-0000-0000-000000000024','00000001-0000-0000-0000-000000000024','Viragos Alom Dekorator','viragos.alom.dekor.test@gmail.com','+36301239876','Teljes esküvői dekoráció: asztaldíszek, székborítók, kapudekor, fénydekoráció. Helyszíni felmérés ingyenes. Bármilyen stílusban dolgozunk, igényeidhez igazodva.','dekor-kellek','Budapest','https://viragosalom.hu',null,'approved',107,now() - interval '60 days'),
